// // This module implements a 4-bit Johnson counter that counts down from 15 to 0 and then wraps around to 15.
module johnson_counter_4 
(
  input rst,
  input clk,

  output reg [3:0] count
);

  always @(posedge clk or posedge rst) begin
    if (rst) 
	begin
      count <= 4'b0000;
    end 
	else 
	begin
      count <= {~count[0], count[3:1]};
    end
  end

endmodule
